module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const grid = String(args.grid) !== 'false';
let lvN = parseInt(args.levels, 10); const levels = (lvN >= 1 && lvN <= 8) ? lvN : 4;
const showvalues = String(args.showvalues) === 'true';
let szN = parseInt(args.size, 10); const size = (szN >= 120 && szN <= 800) ? szN : 360;
let flN = parseInt(args.fill, 10); const fill = (flN >= 0 && flN <= 100) ? flN : 25;
const axes = [];
sections.join('\n').split('\n').map((l) => l.trim()).filter(Boolean).forEach((l) => {
  const i = l.indexOf(':');
  if (i < 0) return;
  const vals = l.slice(i + 1).split(',').map((v) => parseFloat(v)).filter(Number.isFinite);
  if (vals.length) axes.push({ label: l.slice(0, i).trim(), vals });
});
if (axes.length < 3) return `<div>(radar: at least 3 "Label: value" lines)</div>`;
const nSeries = Math.min(2, Math.max(...axes.map((a) => a.vals.length)));
let max = parseFloat(args.max);
if (!Number.isFinite(max) || max <= 0) max = Math.max(...axes.flatMap((a) => a.vals));
const C = 80, R = 56, n = axes.length;
const pt = (i, v) => {
  const th = -Math.PI / 2 + (2 * Math.PI * i) / n;
  const r = R * Math.max(0, Math.min(1, v / max));
  return [C + r * Math.cos(th), C + r * Math.sin(th)];
};
const f = (v) => v.toFixed(1);
let svg = '';
if (grid) {
  for (let lv = 1; lv <= levels; lv++) {
    const k = lv / levels;
    svg += `<polygon points="${axes.map((_, i) => pt(i, max * k).map(f).join(',')).join(' ')}" class="mdp-rd-ring"/>`;
  }
}
axes.forEach((a, i) => {
  const [x, y] = pt(i, max);
  if (grid) svg += `<line x1="${C}" y1="${C}" x2="${f(x)}" y2="${f(y)}" class="mdp-rd-spoke"/>`;
  const [lx, ly] = pt(i, max * 1.22);
  svg += `<text x="${f(lx)}" y="${f(ly)}" class="mdp-rd-lbl" text-anchor="middle" dominant-baseline="middle">${esc(a.label)}</text>`;
});
const colors = [args.color || 'var(--accent-color)', args.color2 || '#ef4444'];
for (let s = 0; s < nSeries; s++) {
  const pts = axes.map((a, i) => pt(i, a.vals[Math.min(s, a.vals.length - 1)]).map(f).join(',')).join(' ');
  svg += `<polygon points="${pts}" class="mdp-rd-series" style="--rd-c:${colors[s]};"/>`;
}
if (showvalues) {
  for (let s = 0; s < nSeries; s++) {
    axes.forEach((a, i) => {
      const v = a.vals[Math.min(s, a.vals.length - 1)];
      const [vx, vy] = pt(i, v);
      svg += `<text x="${f(vx)}" y="${f(vy - 2)}" class="mdp-rd-val" text-anchor="middle" dominant-baseline="middle" style="fill:${colors[s]};">${esc(String(v))}</text>`;
    });
  }
}
let legend = '';
const names = String(args.series || '').split(',').map((x) => x.trim()).filter(Boolean);
if (names.length) {
  legend = `<div class="mdp-rd-legend">` + names.slice(0, nSeries).map((nm, i) =>
    `<span><i style="background:${colors[i]};"></i>${esc(nm)}</span>`).join('') + `</div>`;
}
return `\n\n<div class="mdp-mod-radar" style="--rd-size:${size}px; --rd-fill:${fill}%;"><svg viewBox="0 0 160 160" preserveAspectRatio="xMidYMid meet">${svg}</svg>${legend}</div>\n\n`;
